// v0.14 — Main Menu + Cookie Save System
// ═══════════════════════════════════════════════════════════════
(function installV14MainMenuAndCookieSave() {
  var V14_VERSION = 'v0.14-main-menu-cookie-save';
  var LOGO_URI = 'data:image/webp;base64,';
  var SAVE_COOKIE_META = 'buildYourLegendSaveMeta';
  var SAVE_COOKIE_PREFIX = 'buildYourLegendSavePart_';
  var SAVE_COOKIE_MAX_DAYS = 365;
  var SAVE_CHUNK_SIZE = 3400;

  function setCookie(name, value, days) {
    var expires = '';
    if (days) {
      var date = new Date();
      date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
      expires = '; expires=' + date.toUTCString();
    }
    document.cookie = name + '=' + value + expires + '; path=/; SameSite=Lax';
  }

  function getCookie(name) {
    var nameEQ = name + '=';
    var ca = document.cookie.split(';');
    for (var i = 0; i < ca.length; i++) {
      var c = ca[i];
      while (c.charAt(0) === ' ') c = c.substring(1, c.length);
      if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
    }
    return null;
  }

  function deleteCookie(name) {
    document.cookie = name + '=; Max-Age=0; path=/; SameSite=Lax';
  }

  function clearCookieSave() {
    var meta = parseInt(getCookie(SAVE_COOKIE_META) || '0', 10);
    if (!isNaN(meta) && meta > 0) {
      for (var i = 0; i < meta; i++) deleteCookie(SAVE_COOKIE_PREFIX + i);
    } else {
      for (var j = 0; j < 40; j++) deleteCookie(SAVE_COOKIE_PREFIX + j);
    }
    deleteCookie(SAVE_COOKIE_META);
  }

  function encodeSaveString(str) {
    return btoa(unescape(encodeURIComponent(str)));
  }

  function decodeSaveString(str) {
    return decodeURIComponent(escape(atob(str)));
  }

  function writeCookieSave(obj) {
    var encoded = encodeSaveString(JSON.stringify(obj));
    clearCookieSave();
    var parts = Math.ceil(encoded.length / SAVE_CHUNK_SIZE);
    for (var i = 0; i < parts; i++) {
      setCookie(SAVE_COOKIE_PREFIX + i, encoded.slice(i * SAVE_CHUNK_SIZE, (i + 1) * SAVE_CHUNK_SIZE), SAVE_COOKIE_MAX_DAYS);
    }
    setCookie(SAVE_COOKIE_META, String(parts), SAVE_COOKIE_MAX_DAYS);
  }

  function readCookieSave() {
    var meta = parseInt(getCookie(SAVE_COOKIE_META) || '0', 10);
    if (!meta || isNaN(meta)) return null;
    var encoded = '';
    for (var i = 0; i < meta; i++) {
      var part = getCookie(SAVE_COOKIE_PREFIX + i);
      if (!part) return null;
      encoded += part;
    }
    return JSON.parse(decodeSaveString(encoded));
  }

  function hasAnySave() {
    try { if (getCookie(SAVE_COOKIE_META)) return true; } catch(e) {}
    try { return !!localStorage.getItem('animeRPG_v1'); } catch(e) { return false; }
  }

  function setMenuMsg(txt, color) {
    var el = document.getElementById('menu-msg');
    if (el) {
      el.textContent = txt || '';
      if (color) el.style.color = color;
    }
  }

  var _showSaveMsgV14Prev = showSaveMsg;
  showSaveMsg = function(txt, color) {
    _showSaveMsgV14Prev(txt, color);
    setMenuMsg(txt, color || '#8aaac8');
  };

  var _saveGameV14Prev = saveGame;
  saveGame = function() {
    try { if (!G.save_meta || typeof G.save_meta !== 'object') G.save_meta = {}; } catch(e) {}
    try { G.save_meta.version = V14_VERSION; G.save_meta.lastSaved = new Date().toISOString(); } catch(e) {}
    var result = true;
    try { if (typeof _saveGameV14Prev === 'function') _saveGameV14Prev(); } catch(e) { result = false; }
    try { writeCookieSave(G); } catch(e) {
      showSaveMsg('Cookie save failed: ' + e.message, '#ff4757');
      return false;
    }
    showSaveMsg('✓ Saved to browser cookies at ' + new Date().toLocaleTimeString(), '#2ecc71');
    return result;
  };

  var _loadGameV14Prev = loadGame;
  loadGame = function() {
    var cookieData = null;
    try { cookieData = readCookieSave(); } catch(e) {
      showSaveMsg('Cookie save is unreadable: ' + e.message, '#ff4757');
      return false;
    }
    if (cookieData) {
      try { localStorage.setItem('animeRPG_v1', JSON.stringify(cookieData)); } catch(e) {}
    }
    var hadLocal = false;
    try { hadLocal = !!localStorage.getItem('animeRPG_v1'); } catch(e) {}
    if (!cookieData && !hadLocal) {
      showSaveMsg('No save file found.', '#ff4757');
      return false;
    }
    try { if (typeof _loadGameV14Prev === 'function') _loadGameV14Prev(); } catch(e) {
      showSaveMsg('Load failed: ' + e.message, '#ff4757');
      return false;
    }
    if (G && G.name && G.race_id && G.jobs && G.jobs.length) {
      try { town_center(); } catch(e) {}
    }
    showSaveMsg('✓ Loaded save successfully!', '#2ecc71');
    return true;
  };

  confirmNewGame = function() {
    if (!confirm('Start a new game? Your current cookie save will be cleared.')) return;
    try { clearCookieSave(); } catch(e) {}
    try { localStorage.removeItem('animeRPG_v1'); } catch(e) {}
    try { sessionStorage.setItem('byl_start_new', '1'); } catch(e) {}
    location.reload();
  };

  function updateHeaderBranding() {
    var title = document.querySelector('#game-header h2');
    if (title) title.textContent = '⚔ BUILD YOUR LEGEND ⚔';
    var sub = document.querySelector('#game-header .subtitle');
    if (sub) sub.textContent = 'Fantasy · Text-Based RPG · Forge Your Path';
    document.title = 'Build Your Legend';
  }

  function resetHeaderStatsForMenu() {
    var ids = {
      's-name':'—', 's-class':'—', 's-level':'1', 's-hp':'—', 's-mp':'—', 's-gold':'0'
    };
    Object.keys(ids).forEach(function(id) {
      var el = document.getElementById(id);
      if (el) el.textContent = ids[id];
    });
  }

  window.main_menu = function() {
    updateHeaderBranding();
    resetHeaderStatsForMenu();
    clearOutput();
    showBattlePanel(false);
    if ($ch) $ch.innerHTML = '';
    var out = document.getElementById('output');
    if (!out) return;
    out.innerHTML = '';

    var shell = document.createElement('div');
    shell.className = 'menu-shell';
    var card = document.createElement('div');
    card.className = 'main-menu-card';

    var logo = document.createElement('img');
    logo.className = 'main-menu-logo';
    logo.src = LOGO_URI;
    logo.alt = 'Build Your Legend';
    card.appendChild(logo);

    var title = document.createElement('div');
    title.className = 'main-menu-title';
    title.textContent = 'BUILD YOUR LEGEND';
    card.appendChild(title);

    var sub = document.createElement('div');
    sub.className = 'main-menu-subtitle';
    sub.textContent = 'TEXT-BASED RPG · RACE EVOLUTION · JOB MASTERY';
    card.appendChild(sub);

    var blurb = document.createElement('div');
    blurb.className = 'main-menu-blurb';
    blurb.textContent = 'Begin a new legend, load your saved journey, or adjust the game from Settings. Choose a race, master your current class, evolve one path at a time, and build a character that feels uniquely yours.';
    card.appendChild(blurb);

    var msg = document.createElement('div');
    msg.id = 'menu-msg';
    msg.textContent = hasAnySave() ? 'Save detected. You can continue by using Load Save.' : 'No save detected yet. Start a new game to begin your journey.';
    msg.style.color = hasAnySave() ? '#8aaac8' : '#7e96b5';
    card.appendChild(msg);

    var actions = document.createElement('div');
    actions.className = 'main-menu-actions';

    var newBtn = document.createElement('button');
    newBtn.className = 'main-menu-btn';
    newBtn.textContent = '✨ Start New Game';
    newBtn.onclick = function() {
      if (hasAnySave() && !confirm('A save already exists. Starting fresh will clear that save. Continue?')) return;
      try { clearCookieSave(); } catch(e) {}
      try { localStorage.removeItem('animeRPG_v1'); } catch(e) {}
      try { sessionStorage.setItem('byl_start_new', '1'); } catch(e) {}
      location.reload();
    };
    actions.appendChild(newBtn);

    var loadBtn = document.createElement('button');
    loadBtn.className = 'main-menu-btn secondary';
    loadBtn.textContent = '📂 Load Save';
    loadBtn.disabled = !hasAnySave();
    loadBtn.onclick = function() { loadGame(); };
    actions.appendChild(loadBtn);

    var settingsBtn = document.createElement('button');
    settingsBtn.className = 'main-menu-btn ghost';
    settingsBtn.textContent = '⚙ Settings';
    settingsBtn.onclick = function() { toggleSettings(); };
    actions.appendChild(settingsBtn);

    card.appendChild(actions);

    var note = document.createElement('div');
    note.className = 'main-menu-note';
    note.innerHTML = 'Save data is now written to <strong>browser cookies</strong> (with a local browser backup when available). Use the same browser/device to load your progress.';
    card.appendChild(note);

    shell.appendChild(card);
    out.appendChild(shell);
  };

  function injectV14SettingsNote() {
    var panel = document.getElementById('settings-panel');
    if (!panel || document.getElementById('v14-settings-section')) return;
    var saveSection = Array.prototype.slice.call(panel.querySelectorAll('.sp-section')).find(function(s){ return /Save \/ Load/.test(s.textContent || ''); });
    var div = document.createElement('div');
    div.className = 'sp-section';
    div.id = 'v14-settings-section';
    div.innerHTML = '<h3>Update v0.14</h3><div style="font-size:11px;color:#8aaac8;line-height:1.55;margin-bottom:8px">Added a new main menu, Build Your Legend branding, and cookie-based save / load support.</div><div style="display:flex;gap:6px;flex-wrap:wrap"><button class="sp-btn" onclick="main_menu(); closeSettingsPanel();">🏠 Main Menu</button><button class="sp-btn" onclick="saveGame()">🍪 Save to Cookies</button><button class="sp-btn" onclick="loadGame()">📂 Load Save</button></div>';
    if (saveSection) panel.insertBefore(div, saveSection); else panel.appendChild(div);
  }

  injectV14SettingsNote();
  updateHeaderBranding();

  try {
    if (sessionStorage.getItem('byl_start_new') === '1') {
      sessionStorage.removeItem('byl_start_new');
      pick_race();
    } else {
      main_menu();
    }
  } catch(e) {
    main_menu();
  }
})();


